import { useLocation, useNavigate } from "react-router-dom";
import { useState } from "react";
import api from "../../api/axios";

export default function CustomerBookAppointment() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const submit = async (e) => {
    e.preventDefault();
    try {
      await api.post("/customer/appointments/book", {
        vehicle: state.vehicleId,
        date,
        time,
      });
      alert("Appointment booked!");
      navigate("/my-appointments"); // customer list page
    } catch (err) {
      alert(err.response?.data?.message || "Booking failed");
    }
  };

  return (
    <form onSubmit={submit} style={{ padding: 20 }}>
      <h2>Book Appointment</h2>

      <label>Date</label><br />
      <input type="date" value={date} onChange={(e) => setDate(e.target.value)} required /><br /><br />

      <label>Time</label><br />
      <input type="time" value={time} onChange={(e) => setTime(e.target.value)} required /><br /><br />

      <button type="submit">Submit</button>
    </form>
  );
}
